import { computePosition, autoUpdate, flip, offset, type Placement } from '@floating-ui/dom';
import { createAttachmentKey } from 'svelte/attachments';

interface PopoverOptions {
	interaction?: 'click' | 'hover';
	placement?: Placement;
}

export class Popover {
	private options: PopoverOptions = {
		interaction: 'click',
		placement: 'bottom-start',
	};
	private open = $state(false);
	private referenceElement: HTMLElement | undefined = $state();
	private floatingElement: HTMLElement | undefined = $state();

	constructor(options?: PopoverOptions) {
		if (options) this.options = { ...this.options, ...options };
		$effect(() => {
			if (!this.referenceElement || !this.floatingElement) return;
			return autoUpdate(this.referenceElement, this.floatingElement, this.#updatePosition);
		});
	}

	reference() {
		const attrs = {
			[createAttachmentKey()]: (node: HTMLElement) => {
				this.referenceElement = node;
			},
			onclick: () => {},
			onmouseover: () => {},
			onmouseout: () => {},
		};
		// If click interaction
		if (this.options.interaction === 'click') {
			attrs['onclick'] = () => {
				this.open = !this.open;
			};
		}
		// If hover interaction
		if (this.options.interaction === 'hover') {
			attrs['onclick'] = () => {
				this.open = !this.open;
			};
			attrs['onmouseover'] = () => {
				this.open = true;
			};
			attrs['onmouseout'] = () => {
				this.open = false;
			};
		}
		return attrs;
	}

	floating() {
		return {
			[createAttachmentKey()]: (node: HTMLElement) => {
				this.floatingElement = node;
			},
		};
	}

	isOpen() {
		return this.open;
	}

	#updatePosition = async () => {
		if (!this.referenceElement || !this.floatingElement) {
			return;
		}
		const position = await computePosition(this.referenceElement, this.floatingElement, {
			placement: this.options.placement,
			middleware: [flip(), offset(8)],
		});
		const { x, y } = position;
		Object.assign(this.floatingElement.style, {
			left: `${x}px`,
			top: `${y}px`,
		});
	};
}

import { glob } from 'astro/loaders';
import { defineCollection } from 'astro:content';
import { Octokit } from 'octokit';
import { z } from 'astro/zod';

export const collections = {
	frameworks: defineCollection({
		loader: glob({
			base: './src/content/frameworks',
			pattern: '*.json',
		}),
		schema: z.object({
			name: z.string().nonempty(),
			logo: z.string().nonempty(),
			default: z.boolean().optional().default(false),
		}),
	}),
	docs: defineCollection({
		loader: glob({
			base: './src/content/docs',
			pattern: '**/*.{md,mdx}',
		}),
		schema: z.object({
			title: z.string().nonempty(),
			description: z.string().nonempty(),
			summary: z.string().optional(),
			features: z.array(z.string()).optional(),
			stability: z.enum(['alpha', 'beta', 'stable']).optional().default('stable'),
			order: z.number().nonnegative().optional().default(0),
			tags: z.array(z.string()).optional().default([]),
			references: z
				.object({
					source: z.union([z.url(), z.literal(false)]).optional(),
					styles: z.union([z.url(), z.literal(false)]).optional(),
					a11y: z.union([z.url(), z.literal(false)]).optional(),
					zag: z.union([z.url(), z.literal(false)]).optional(),
				})
				.optional()
				.default({}),
		}),
	}),
	contributors: defineCollection({
		loader: async () => {
			if (process.env.VERCEL_ENV !== 'production') {
				return Array.from({ length: 100 }).map((_, index) => ({
					id: String(index),
					html_url: `https://github.com/user-${index}`,
					avatar_url: `https://picsum.photos/100`,
					login: `user-${index}`,
				}));
			}
			const octokit = new Octokit();
			const response = await octokit.rest.repos.listContributors({
				owner: 'skeletonlabs',
				repo: 'skeleton',
				per_page: 100,
			});
			return response.data
				.filter((contributor) => !!contributor.id)
				.map((contributor) => ({
					...contributor,
					id: String(contributor.id),
				}));
		},
		schema: z.object({
			html_url: z.url(),
			avatar_url: z.url(),
			login: z.string(),
		}),
	}),
	'showcase-projects': defineCollection({
		loader: glob({
			base: './src/content/showcase-projects',
			pattern: '*.json',
		}),
		schema: z.object({
			name: z.string(),
			description: z.string(),
			url: z.url(),
			playwright: z
				.object({
					instructions: z.array(z.string()),
				})
				.optional(),
		}),
	}),
};

